  const slackComponents = JSON.stringify({ available: ['client', 'loadbalancer', 'server', 'database', 'cache', 'cdn', 'queue', 'storage', 'monitoring', 'apigateway'], required: ['client', 'loadbalancer', 'server', 'database', 'cache', 'queue'], hints: ['WebSocket connections are stateful — a sticky load balancer (consistent hashing by user_id) routes reconnects to the same gateway node, preserving session state without a round-trip to the cache', 'Fan-out uses a pub/sub layer (Redis Pub/Sub or Kafka): the message is written once to the broker which broadcasts to all subscribers for that channel — direct server-to-server push does not scale beyond ~10K connections per node', 'Channel history lives in a sharded DB (shard key: workspace_id) — cursor pagination uses a composite index on (channel_id, message_id DESC); OFFSET is forbidden at this scale because it degrades to O(n)', 'Cache stores the last 100 messages per channel (hot path) so timeline loads never touch the DB; older history falls through to the sharded message store', 'Presence is tracked via Redis TTL keys: every client heartbeats every 30s to reset the TTL — no persistent connection tracking, no DELETE on disconnect'] });
  await prisma.mission.upsert({ where: { slug: 'design-slack' }, update: { components: slackComponents, learningPath: 'real-time', skillLevel: 'advanced' }, create: { slug: 'design-slack', title: 'Mission 18: How Slack Works', difficulty: 5, estimatedTime: '40-50 min', xpReward: 450, order: 18, learningPath: 'real-time', skillLevel: 'advanced', description: 'Design the real-time messaging backend for a Slack-scale platform: WebSocket fan-out, workspace sharding, cursor-based history, and TTL-based presence for 20M DAU.', scenario: "Slack has 20M daily active users across 500K workspaces. A message sent in a 10K-member channel must be delivered to all online members in under 500ms. Design the real-time messaging backend: WebSocket connection management, message fan-out, channel history pagination, and workspace-level database sharding.", objectives: JSON.stringify(['Support 1M concurrent WebSocket connections across the fleet','Fan out a message to 10K channel members in under 500ms','Paginate channel history with cursor-based pagination — no OFFSET queries','Shard the database by workspace_id to isolate tenant data','Maintain 99.99% uptime with graceful WebSocket reconnection']), requirements: JSON.stringify({ traffic: { concurrent: 1000000, peakMessagesPerSecond: 100000, daily: 5000000000 }, performance: { latencyMs: 500, historyLoadMs: 200, availability: 99.99 }, budget: 75000, growth: '20M DAU, 500K workspaces, channels up to 10K members', required: ['client', 'loadbalancer', 'server', 'database', 'cache', 'queue'], bonus: [{ component: 'monitoring', xp: 30, label: 'Instrument WebSocket connection count, message delivery lag, and fan-out queue depth (+30 XP)' },{ component: 'cdn', xp: 25, label: 'Serve static assets (emoji, avatars) via CDN to reduce origin load (+25 XP)' },{ component: 'apigateway', xp: 35, label: 'Route REST API calls (file uploads, search) separately from WebSocket traffic (+35 XP)' }] }), components: slackComponents, feedbackData: JSON.stringify({ learned: ['WebSocket fan-out at scale requires a pub/sub intermediary — direct server-to-server push does not scale past ~10K connections per node', 'Sharding by workspace_id gives strong tenant isolation — cross-workspace queries are rare and handled by a separate search index', 'Cursor-based pagination (keyset pagination) is mandatory for chat history — OFFSET degrades to O(n) at large offsets', 'Presence systems use TTL-based heartbeats, not persistent connections — Redis EXPIRE is cheaper than tracking every disconnect event', 'Thread reply fan-out is a separate concern — replies fan out only to thread participants, not the full channel'], nextMission: 'design-twitter-timeline', nextPreview: 'Scale & Streaming — fan out tweets to 300M followers without a thundering herd' }) } });

