  // ── M-021: How Uber Computes ETA (consistency path) ───────────────────────────
  const uberEtaComponents = JSON.stringify({ available: ['client', 'loadbalancer', 'server', 'database', 'cache', 'cdn', 'queue', 'storage', 'monitoring', 'apigateway'], required: ['client', 'server', 'database', 'cache', 'queue'], hints: ['Geohashing divides the map into a grid of cells (precision 6 = ~1.2km x 0.6km) — nearby drivers share the same geohash prefix enabling O(1) proximity lookups without expensive radius scans across millions of rows', 'Driver locations are stored in Redis with GEOADD/GEOSEARCH — internally Redis Geo uses a sorted set with geohash scores; GEOSEARCH key FROMLONLAT lon lat BYRADIUS 2 km ASC COUNT 10 returns nearest drivers in microseconds', 'Location updates flow through Kafka before hitting the geo store — this decouples the 1.25M pings/sec ingestion rate from the Redis write throughput absorbing bursts without dropping updates', 'ETA engine queries a pre-computed road graph and overlays real-time traffic weights — it does NOT compute shortest path from scratch per request; Dijkstra runs on a cached graph snapshot updated every 60s', 'Stale location detection: each driver entry has a 10-second TTL in Redis — if no ping arrives within the TTL the driver is automatically marked unavailable with no explicit DELETE operation'] });
  await prisma.mission.upsert({ where: { slug: 'design-uber-eta' }, update: { components: uberEtaComponents, learningPath: 'consistency', skillLevel: 'advanced' }, create: { slug: 'design-uber-eta', title: 'Mission 21: How Uber Computes ETA', difficulty: 5, estimatedTime: '40-50 min', xpReward: 500, order: 21, learningPath: 'consistency', skillLevel: 'advanced', description: "Design the location ingestion pipeline, geospatial index, and ETA computation engine that powers Uber's real-time driver matching at 1.25M GPS pings/sec.", scenario: "Uber processes 5M ride requests per day. Every driver sends a GPS location update every 4 seconds — that is 1.25M location pings per second at peak. When a rider requests a ride, the system must find the nearest available drivers within 500ms and compute an accurate ETA. Design the location ingestion pipeline, geospatial indexing strategy, and ETA computation engine.", objectives: JSON.stringify(['Ingest 1.25M driver GPS pings per second with under 1s write latency','Find all available drivers within a 2km radius in under 200ms','Compute ETA using road network data in under 500ms end-to-end','Handle driver location staleness — expire pings older than 10 seconds automatically','Scale to 50 cities simultaneously with geo-partitioned data']), requirements: JSON.stringify({ traffic: { locationPingsPerSecond: 1250000, rideRequestsPerDay: 5000000, peakEtaQueriesPerSecond: 10000 }, performance: { proximitySearchMs: 200, etaComputationMs: 500, locationWriteLatencyMs: 1000, availability: 99.99 }, budget: 90000, growth: '5M rides/day, 1.25M GPS pings/sec, 50 cities', required: ['client', 'server', 'database', 'cache', 'queue'], bonus: [{ component: 'monitoring', xp: 45, label: 'Track location ingestion lag, proximity search p99, and ETA accuracy vs actual trip time (+45 XP)' },{ component: 'loadbalancer', xp: 35, label: 'Distribute ETA query traffic across computation nodes (+35 XP)' },{ component: 'apigateway', xp: 35, label: 'Separate rider-facing API from driver location ingestion API (+35 XP)' }] }), components: uberEtaComponents, feedbackData: JSON.stringify({ learned: ['Geohashing converts 2D coordinates into a 1D string that can be indexed and range-queried efficiently — it is the key insight for proximity search at scale', 'Redis GEOSEARCH is purpose-built for this use case: GEOSEARCH key FROMLONLAT lon lat BYRADIUS 2 km ASC COUNT 10', 'Location ingestion uses Kafka as a buffer — prevents GPS ping storms from overwhelming the geo store during peak hours', 'ETA is not computed from scratch per request — it uses a pre-computed road graph with real-time traffic overlays updated every 60 seconds', 'Geo-partitioning by city/region keeps data local and reduces cross-region latency for proximity searches'], nextMission: 'design-slack', nextPreview: "Real-Time — design Slack's WebSocket fan-out for 20M DAU" }) } });

  // ── M-022: Build ChatGPT's Backend / How ChatGPT Works (foundations path) ─────
  const chatgptComponents = JSON.stringify({ available: ['client', 'loadbalancer', 'server', 'database', 'cache', 'cdn', 'queue', 'storage', 'monitoring', 'apigateway'], required: ['client', 'apigateway', 'server', 'cache', 'database'], hints: ['GPU inference workers are stateful during a request because the KV-cache (attention key-value state) lives in GPU memory — sticky routing in the load balancer keeps a request on the same GPU worker for its full streaming duration; migrating mid-stream would require transferring gigabytes of GPU state', 'SSE (Server-Sent Events) is preferred over WebSockets for streaming token responses — it is unidirectional (server to client only), works natively over HTTP/2 multiplexing, and auto-reconnects on drop without custom client logic', 'Semantic cache: embed each incoming prompt using a lightweight embedding model, store the vector in a vector DB alongside the cached response, and return the cached result for prompts with cosine similarity above 0.95 — cuts GPU inference for repeated or near-identical prompts', 'Rate limiting uses a token bucket per API key stored in Redis: INCR + EXPIRE executed atomically in a Lua script enforces per-minute limits without race conditions under concurrent requests from the same key', 'Billing metering is always async — count tokens in/out per request, write an event to a Kafka queue, aggregate downstream in a billing service; never block the GPU inference hot path for a billing write'] });
  await prisma.mission.upsert({ where: { slug: 'design-chatgpt' }, update: { components: chatgptComponents, learningPath: 'foundations', skillLevel: 'intermediate' }, create: { slug: 'design-chatgpt', title: "Mission 22: Build ChatGPT's Backend", difficulty: 4, estimatedTime: '35-45 min', xpReward: 300, order: 22, learningPath: 'foundations', skillLevel: 'intermediate', description: 'Design the request routing, GPU inference pipeline, SSE streaming, semantic caching, and async billing metering behind an LLM API serving 100M users.', scenario: "OpenAI's ChatGPT serves 100M users with 1M API requests per day. Users expect streaming token responses (first token in under 500ms), usage-based billing, and rate limiting per API key. Design the backend: request routing, GPU inference pipeline, streaming response delivery via SSE, semantic caching for repeated prompts, and the billing and metering system.", objectives: JSON.stringify(['Route 1M API requests/day to GPU inference workers with under 500ms time-to-first-token','Stream token responses to clients using Server-Sent Events (SSE)','Rate limit by API key: 60 requests/min for free tier and 3600/min for paid tier','Cache semantically similar prompts to reduce GPU compute costs by 20% or more','Meter token usage per API key for usage-based billing without blocking inference']), requirements: JSON.stringify({ traffic: { apiRequestsPerDay: 1000000, peakRequestsPerSecond: 500, avgTokensPerResponse: 500 }, performance: { timeToFirstTokenMs: 500, streamingThroughputTokensPerSec: 50, availability: 99.9 }, budget: 50000, growth: '100M users, 1M requests/day, free and paid tiers, usage-based billing', required: ['client', 'apigateway', 'server', 'cache', 'database'], bonus: [{ component: 'queue', xp: 40, label: 'Decouple billing metering from the inference path using an async queue (+40 XP)' },{ component: 'monitoring', xp: 30, label: 'Track time-to-first-token p50/p99, GPU utilisation, and semantic cache hit rate (+30 XP)' },{ component: 'loadbalancer', xp: 25, label: 'Distribute requests across GPU worker pools with sticky routing (+25 XP)' }] }), components: chatgptComponents, feedbackData: JSON.stringify({ learned: ['GPU inference is the bottleneck — the entire architecture exists to maximise GPU utilisation and minimise idle time between requests', 'SSE is the right protocol for streaming: simpler than WebSockets, supports HTTP/2 multiplexing, and auto-reconnects on network drop', 'Semantic caching is a cost multiplier — a 20% cache hit rate on a $10M GPU bill saves $2M per month', 'Rate limiting must be atomic — Redis INCR + EXPIRE in a Lua script prevents race conditions under concurrent requests from the same API key', 'Billing is always async — never put billing logic in the hot path; use a queue and aggregate downstream'], nextMission: 'design-kafka', nextPreview: 'Async & Queues — design Kafka and understand why it is the backbone of real-time data pipelines' }) } });

  // ── M-023: How Kafka Works (async-queues path) ────────────────────────────────
  const kafkaComponents = JSON.stringify({ available: ['client', 'loadbalancer', 'server', 'database', 'cache', 'cdn', 'queue', 'storage', 'monitoring', 'apigateway'], required: ['client', 'server', 'storage', 'queue', 'database'], hints: ["Kafka's core abstraction is the append-only log: producers write to the tail of a partition log, consumers read from any offset they choose — this is what makes replay, time-travel debugging, and multiple independent consumers possible without coordination", 'Partitions are the unit of parallelism: a topic with 100 partitions can be consumed simultaneously by up to 100 consumers within the same consumer group; adding more partitions is how you scale consumer throughput horizontally', 'The broker is a dumb log store — it does not track consumer state; each consumer group commits its own offsets to the internal __consumer_offsets topic, meaning a slow analytics consumer never blocks a fast payments consumer reading the same log', 'Replication: each partition has one leader and N-1 followers; producers write exclusively to the leader which replicates to followers; ISR (in-sync replicas) is the set of followers caught up within a configurable lag threshold — a message is only acknowledged when all ISR members have written it', 'ZooKeeper (legacy) or KRaft (modern Kafka 3.x) manages broker metadata, controller election, and cluster membership — it is the control plane only; message throughput is entirely independent of ZooKeeper/KRaft load'] });
  await prisma.mission.upsert({ where: { slug: 'design-kafka' }, update: { components: kafkaComponents, learningPath: 'async-queues', skillLevel: 'intermediate' }, create: { slug: 'design-kafka', title: 'Mission 23: How Kafka Works', difficulty: 4, estimatedTime: '40-50 min', xpReward: 350, order: 23, learningPath: 'async-queues', skillLevel: 'intermediate', description: 'Design a distributed event streaming platform: append-only log, partition-level parallelism, independent consumer group offsets, and ISR-based replication at 1M events/sec.', scenario: 'Apache Kafka is the backbone of real-time data pipelines at LinkedIn, Uber, and Netflix. Design a distributed event streaming platform that handles 1M events per second, guarantees ordering within a partition, retains messages for 7 days, and supports consumer groups that can independently replay the event log from any offset.', objectives: JSON.stringify(['Ingest 1M events/second across a cluster of broker nodes','Guarantee message ordering within each partition — not globally across the topic','Retain all messages for 7 days with configurable retention policies','Support consumer groups: each group tracks its own offset independently','Replicate each partition to 3 brokers for fault tolerance (replication factor 3)']), requirements: JSON.stringify({ traffic: { eventsPerSecond: 1000000, avgEventSizeBytes: 1024, retentionDays: 7 }, performance: { producerLatencyMs: 10, consumerLagTargetMs: 1000, availability: 99.99 }, budget: 80000, growth: '1M events/sec, 7-day retention, multiple independent consumer groups, replication factor 3', required: ['client', 'server', 'storage', 'queue', 'database'], bonus: [{ component: 'monitoring', xp: 35, label: 'Track consumer lag per group, broker disk usage, and ISR count per partition (+35 XP)' },{ component: 'apigateway', xp: 35, label: 'Add a schema registry to validate Avro/Protobuf schemas at produce time (+35 XP)' },{ component: 'loadbalancer', xp: 25, label: 'Distribute producer connections across broker nodes (+25 XP)' }] }), components: kafkaComponents, feedbackData: JSON.stringify({ learned: ['The append-only log is the superpower — it enables replay, multiple independent consumers, and time-travel debugging without coordination', 'Partitions equal parallelism: one consumer per partition per group — more partitions means more consumer parallelism', 'Consumer offset ownership is the key design decision: consumers own their offsets so they can replay, skip, or pause independently', 'ISR replication: a message is only acknowledged when all in-sync replicas have written it — this is the durability guarantee that prevents data loss on broker failure', 'Kafka is not a queue — it is a log; messages are not deleted on consumption; they expire based on retention time or size policy'], nextMission: 'design-spotify', nextPreview: 'Async & Queues — design Spotify audio delivery and async recommendation pipeline' }) } });

