  const spotifyComponents = JSON.stringify({ available: ['client', 'loadbalancer', 'server', 'database', 'cache', 'cdn', 'queue', 'storage', 'monitoring', 'apigateway'], required: ['client', 'server', 'storage', 'cdn', 'cache', 'database'], hints: ['Audio delivery is entirely a CDN problem: audio files are pre-encoded in multiple bitrates (96kbps, 160kbps, 320kbps) and cached at edge nodes — the origin server is never contacted during playback; the client receives a time-limited pre-signed CDN URL and streams directly from the edge', 'Offline sync uses a delta sync protocol: the client sends a manifest of its locally cached tracks (track IDs and last-modified timestamps), and the server returns only the diff — new tracks to download and deleted tracks to remove; never transfer the full catalogue per sync', 'Listening events (play, skip, seek, complete) flow through a Kafka queue to the recommendation pipeline — this fully decouples real-time playback from the batch ML processing (Collaborative Filtering, matrix factorisation) that generates Discover Weekly', 'Spotify Connect is a control plane problem not a data plane problem: play/pause/seek commands are tiny JSON messages routed over a WebSocket command channel between devices; the audio bytes themselves never move between devices — only the playback state pointer changes', 'Track metadata (title, artist, album art URLs) is cached in Redis with long TTLs — it changes rarely and is read millions of times per second; album art is served from CDN not from the metadata API'] });
